from typing import Protocol

class Sendable(Protocol):
    def send(self, recipient: str, message: str) -> bool: ...

class Closeable(Protocol):
    def close(self) -> None: ...

# Both classes satisfy Sendable without importing or subclassing it
class EmailBackend:
    def send(self, recipient: str, message: str) -> bool: ...

class SMSBackend:
    def send(self, recipient: str, message: str) -> bool: ...

def dispatch(backend: Sendable, to: str, msg: str) -> bool:
    return backend.send(to, msg)

from django.db import models

class Product(models.Model):
    name = models.CharField(max_length=100)
    is_active = models.BooleanField(default=True)

# django-stubs makes this fully typed
def get_active_products() -> models.QuerySet[Product]:
    return Product.objects.filter(is_active=True)

from typing import cast

def process(value: int | str) -> str:
    # Bad: cast does not check at runtime
    return cast(str, value).upper()

def process(value: int | str) -> str:
    if isinstance(value, str):
        return value.upper()
    return str(value)
